import { NextResponse } from 'next/server';
import { getOrderSheet } from '@/googleSheet'; // 使用 tsconfig 中定义的 @ 别名

export const dynamic = 'force-dynamic';

async function sendSMS(phone: string, time: string, name: string) {
  try {
    console.log(`[SMS] Starting SMS process for phone: ${phone}, time: ${time}`);
    
    // 1. 格式化手机号
    let formattedPhone = phone.trim().replace(/[\s-]/g, '');
    if (formattedPhone.startsWith('0')) {
      formattedPhone = '61' + formattedPhone.substring(1);
    } else if (formattedPhone.startsWith('+')) {
      formattedPhone = formattedPhone.substring(1);
    }
    console.log(`[SMS] Formatted phone for ClickSend: ${formattedPhone}`);

    // 2. 使用 ClickSend REST API (最简单的 HTTP POST)
    const CLICKSEND_USER = 'x813366@gmail.com';
    const CLICKSEND_KEY = 'A9B9B9F1-97D4-91DE-403A-F8C68AD58057';

    const auth = Buffer.from(`${CLICKSEND_USER}:${CLICKSEND_KEY}`).toString('base64');
    
    const response = await fetch('https://rest.clicksend.com/v3/sms/send', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Basic ${auth}`
      },
      body: JSON.stringify({
        messages: [
          {
            source: "sdk",
              body: `Camden RSL Club: Hi ${name}, your order is confirmed for pickup at ${time}. Thank you for ordering with us!`,
              to: formattedPhone
          }
        ]
      })
    });

    const result = await response.json();
    
    if (response.ok && result.data && result.data.messages && result.data.messages[0]) {
      console.log(`[SMS Success] ClickSend status: ${result.data.messages[0].status}, msg: ${result.data.messages[0].status_text}`);
    } else {
      console.error(`[SMS API Error] Response:`, JSON.stringify(result));
    }
    
  } catch (error) {
    console.error('[SMS Error] Failed to send text:', error);
  }
}

export async function GET() {
  try {
    const sheet = await getOrderSheet();
    const rows = await sheet.getRows();
    
    const orders = rows.map(row => ({
      id: row.rowNumber,
      phone: row.get('Phone'),
      name: row.get('Name'),
      dishes: row.get('Dishes'),
      notes: row.get('Notes'),
      pickupTime: row.get('Pickup Time'),
      orderTime: row.get('Order Time'),
      status: row.get('Stauts') || 'Received', // 使用新的 Stauts 列，默认为 Received
    }));

    const sortedOrders = orders.sort((a, b) => {
      // 1. 优先尝试使用时间戳排序
      const timeA = a.orderTime ? new Date(a.orderTime).getTime() : 0;
      const timeB = b.orderTime ? new Date(b.orderTime).getTime() : 0;

      // 如果时间解析有效且不相等，按时间降序
      if (!isNaN(timeA) && !isNaN(timeB) && timeA !== timeB) {
        return timeB - timeA;
      }

      // 2. 如果时间无效或相等，使用行号 (ID) 降序作为兜底
      // 在 Google Sheets 中，行号越大代表数据越新
      return b.id - a.id;
    }).slice(0, 10); // 获取前 10 个最新订单

    return NextResponse.json(sortedOrders);
  } catch (error: any) {
    console.error('Error fetching orders:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const { id, status, pickupTime } = await req.json();
    console.log(`[API POST] Received request - ID: ${id}, Target Status: ${status}, New PickupTime: ${pickupTime}`);

    const sheet = await getOrderSheet();
    const rows = await sheet.getRows();
    
    // 找到对应的行（rowNumber 是从 1 开始的索引）
    const row = rows.find(r => r.rowNumber === id);
    if (row) {
      let finalPickupTime = (pickupTime || row.get('Pickup Time') || '').toString().trim();
      
      // 匹配 ASAP 或 ASAP:分钟 (例如 ASAP:30)
      const asapMatch = finalPickupTime.match(/^ASAP(?::(\d+))?$/i);

      if (asapMatch) {
        // 如果有冒号后的数字则使用它，否则默认 15 分钟
        const offsetMinutes = asapMatch[1] ? parseInt(asapMatch[1], 10) : 15;
        const sydneyDate = new Date(Date.now() + offsetMinutes * 60 * 1000);
        
        // 使用 en-GB 区域设置和 Australia/Sydney 时区确保获取准确的 24h 格式悉尼时间
        finalPickupTime = sydneyDate.toLocaleTimeString('en-GB', {
          timeZone: 'Australia/Sydney',
          hour: '2-digit',
          minute: '2-digit',
          hour12: false
        });
        row.set('Pickup Time', finalPickupTime);
      } else if (pickupTime) {
        row.set('Pickup Time', pickupTime);
      }
      
      // 如果状态变为 Confirmed，发送短信
      if (status === 'Confirmed') {
        const phone = row.get('Phone');
        const name = row.get('Name');
        console.log(`[API POST] Triggering SMS for Order ${id} to ${name} (${phone})`);
        await sendSMS(phone, finalPickupTime, name);
      }

      row.set('Stauts', status); // 更新到 Stauts 列
      await row.save();
      return NextResponse.json({ success: true, pickupTime: finalPickupTime });
    }
    return NextResponse.json({ error: 'Order not found' }, { status: 404 });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}